import React, { useState, useEffect, useContext } from "react";
import { useNavigate } from "react-router-dom";
import io from "socket.io-client";
import {
  Button,
  TextField,
  Box,
  Paper,
  Typography,
  List,
  ListItem,
  ListItemText,
  Grid,
  Divider,
} from "@mui/material";
import { AuthContext } from "../contexts/AuthContext";

const Lobby = () => {
  const { isAuthenticated } = useContext(AuthContext);
  const [socket, setSocket] = useState(null);
  const [rooms, setRooms] = useState([]);
  const [newRoomName, setNewRoomName] = useState("");
  const navigate = useNavigate();

  useEffect(() => {
    if (!isAuthenticated) {
      navigate("/login");
      return;
    }

    const newSocket = io("http://localhost:3000");
    setSocket(newSocket);

    newSocket.on("roomList", (roomList) => {
      setRooms(roomList);
    });

    newSocket.on("roomCreated", ({ roomName }) => {
      newSocket.emit("getRooms");
    });

    newSocket.on("roomClosed", (closedRoomName) => {
      newSocket.emit("getRooms");
    });

    newSocket.emit("getRooms");

    return () => newSocket.close();
  }, [isAuthenticated, navigate]);

  const createRoom = () => {
    if (newRoomName && socket) {
      socket.emit("createRoom", newRoomName);
      setNewRoomName("");
    }
  };

  const joinRoom = (roomName) => {
    if (socket) {
      socket.emit("joinRoom", roomName);
      navigate(`/chat/${roomName}`);
    }
  };

  return (
    <Box sx={{ maxWidth: 600, margin: "auto", mt: 4 }}>
      {isAuthenticated ? (
        <Paper elevation={3} sx={{ p: 3 }}>
          <Typography variant="h5" gutterBottom>
            聊天室大廳
          </Typography>
          <Grid container spacing={2} sx={{ mb: 2 }}>
            <Grid item xs={8}>
              <TextField
                fullWidth
                value={newRoomName}
                onChange={(e) => setNewRoomName(e.target.value)}
                placeholder="輸入新房間名稱"
                variant="outlined"
                size="small"
              />
            </Grid>
            <Grid item xs={4}>
              <Button
                fullWidth
                variant="contained"
                onClick={createRoom}
                disabled={!newRoomName}
              >
                創建房間
              </Button>
            </Grid>
          </Grid>
          <Divider sx={{ my: 2 }} />
          <Typography variant="h6" gutterBottom>
            可用房間
          </Typography>
          <List>
            {rooms.map((room) => (
              <ListItem key={room.name} disablePadding>
                <ListItemText
                  primary={room.name}
                  secondary={`用戶數: ${room.userCount} | 最後消息: ${
                    room.lastMessage?.text || "無"
                  }`}
                />
                <Button variant="outlined" onClick={() => joinRoom(room.name)}>
                  加入
                </Button>
              </ListItem>
            ))}
          </List>
        </Paper>
      ) : (
        <Typography variant="h6">請先登入以訪問大廳</Typography>
      )}
    </Box>
  );
};

export default Lobby;
